@using sv_2394f1f864a348b596cec202828b6c36.Services

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted text-uppercase fw-semibold" style="font-size: 0.75rem; letter-spacing: 0.05em;">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in _sections)
        {
            <li class="nav-item">
                <button class="nav-link settings-nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="me-2">@section.Value.Icon</span>
                    @section.Value.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["Profile"] = ("Profile", "👤"),
        ["Notifications"] = ("Notifications", "🔔"),
        ["Security"] = ("Security", "🔒"),
        ["Appearance"] = ("Appearance", "🎨")
    };
}

.settings-sidebar {
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
    height: 100%;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    width: 100%;
    padding: 0.6rem 1.25rem;
    border: none;
    background: none;
    color: #495057;
    font-size: 0.95rem;
    text-align: left;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.settings-nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

@using sv_2394f1f864a348b596cec202828b6c36.Services
@inject ISettingsService SettingsService

<div class="p-4">
    <h4 class="mb-4">Profile Settings</h4>

    @if (_loading)
    {
        <div class="text-center py-5"><div class="spinner-border text-primary"></div></div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4">
                <div class="text-center">
                    <label class="form-label fw-semibold d-block">Avatar</label>
                    <div class="avatar-preview mb-2">
                        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" style="width: 120px; height: 120px; object-fit: cover; border: 3px solid #dee2e6;" />
                    </div>
                    <small class="text-muted d-block text-truncate" style="max-width: 200px;" title="@_avatarUrl">@_avatarUrl</small>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _message = "Profile saved successfully!";
        _saving = false;
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _message = null;
    }
}

@using sv_2394f1f864a348b596cec202828b6c36.Services
@inject ISettingsService SettingsService

<div class="p-4">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_loading)
    {
        <div class="text-center py-5"><div class="spinner-border text-primary"></div></div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title text-muted text-uppercase" style="font-size: 0.75rem; letter-spacing: 0.05em;">General</h6>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" role="switch" id="emailNotif" @bind="_emailNotifications" />
                    <label class="form-check-label" for="emailNotif">
                        <strong>Email Notifications</strong>
                        <br /><small class="text-muted">Receive notifications via email</small>
                    </label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" role="switch" id="pushNotif" @bind="_pushNotifications" />
                    <label class="form-check-label" for="pushNotif">
                        <strong>Push Notifications</strong>
                        <br /><small class="text-muted">Receive browser push notifications</small>
                    </label>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch" id="weeklyDigest" @bind="_weeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">
                        <strong>Weekly Digest</strong>
                        <br /><small class="text-muted">Get a weekly summary of activity</small>
                    </label>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title text-muted text-uppercase" style="font-size: 0.75rem; letter-spacing: 0.05em;">Muted Channels</h6>
                <p class="text-muted small">Uncheck channels you want to receive notifications from.</p>
                @foreach (var channel in _allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private readonly List<string> _allChannels = ["announcements", "marketing", "social", "engineering", "general"];

    private bool _loading = true;
    private bool _saving;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _message = "Notification preferences saved!";
        _saving = false;
    }
}

@using sv_2394f1f864a348b596cec202828b6c36.Services

@if (_visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    @if (Session is not null)
                    {
                        <div class="bg-light rounded p-3">
                            <strong>@Session.Device</strong><br />
                            <small class="text-muted">@Session.Location &middot; Last active @FormatTime(Session.LastActive)</small>
                        </div>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private bool _visible => Session is not null;

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();

    private static string FormatTime(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_2394f1f864a348b596cec202828b6c36.Services
@inject ISettingsService SettingsService

<div class="p-4">
    <h4 class="mb-4">Security Settings</h4>

    @if (_loading)
    {
        <div class="text-center py-5"><div class="spinner-border text-primary"></div></div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <ChangePasswordPanel OnPasswordChanged="HandlePasswordChange" />

        <!-- Two-Factor Authentication -->
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <small class="text-muted">Add an extra layer of security to your account</small>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_twoFactorEnabled" @onchange="Toggle2FA" />
                    </div>
                </div>
            </div>
        </div>

        @if (_lastPasswordChange.HasValue)
        {
            <p class="text-muted small mb-4">
                Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }

        <!-- Active Sessions -->
        <div class="card">
            <div class="card-header">
                <h6 class="mb-0">Active Sessions</h6>
            </div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (session == _sessions.FirstOrDefault())
                                        {
                                            <span class="badge bg-primary ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatTime(session.LastActive)</td>
                                    <td class="text-end">
                                        @if (session != _sessions.FirstOrDefault())
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => _sessionToRevoke = session">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        <RevokeSessionDialog Session="_sessionToRevoke"
                             OnConfirm="RevokeSessionAsync"
                             OnCancel="() => _sessionToRevoke = null" />
    }
</div>

@code {
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;

    private bool _loading = true;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
        _loading = false;
    }

    private async Task LoadAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
    }

    private void Toggle2FA(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)(e.Value ?? false);
    }

    private async Task HandlePasswordChange()
    {
        await SettingsService.ChangePasswordAsync("", "");
        _lastPasswordChange = DateTime.UtcNow;
        _message = "Password changed successfully!";
    }

    private async Task RevokeSessionAsync()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions.Remove(_sessionToRevoke);
        _sessionToRevoke = null;
        _message = "Session revoked.";
    }

    private static string FormatTime(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

