@using sv_2394f1f864a348b596cec202828b6c36.Services
@inject ISettingsService SettingsService

<div class="p-4">
    <h4 class="mb-4">Security Settings</h4>

    @if (_loading)
    {
        <div class="text-center py-5"><div class="spinner-border text-primary"></div></div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <ChangePasswordPanel OnPasswordChanged="HandlePasswordChange" />

        <!-- Two-Factor Authentication -->
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <small class="text-muted">Add an extra layer of security to your account</small>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_twoFactorEnabled" @onchange="Toggle2FA" />
                    </div>
                </div>
            </div>
        </div>

        @if (_lastPasswordChange.HasValue)
        {
            <p class="text-muted small mb-4">
                Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }

        <!-- Active Sessions -->
        <div class="card">
            <div class="card-header">
                <h6 class="mb-0">Active Sessions</h6>
            </div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (session == _sessions.FirstOrDefault())
                                        {
                                            <span class="badge bg-primary ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatTime(session.LastActive)</td>
                                    <td class="text-end">
                                        @if (session != _sessions.FirstOrDefault())
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => _sessionToRevoke = session">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        <RevokeSessionDialog Session="_sessionToRevoke"
                             OnConfirm="RevokeSessionAsync"
                             OnCancel="() => _sessionToRevoke = null" />
    }
</div>

@code {
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;

    private bool _loading = true;
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
        _loading = false;
    }

    private async Task LoadAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
    }

    private void Toggle2FA(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)(e.Value ?? false);
    }

    private async Task HandlePasswordChange()
    {
        await SettingsService.ChangePasswordAsync("", "");
        _lastPasswordChange = DateTime.UtcNow;
        _message = "Password changed successfully!";
    }

    private async Task RevokeSessionAsync()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions.Remove(_sessionToRevoke);
        _sessionToRevoke = null;
        _message = "Session revoked.";
    }

    private static string FormatTime(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

