@using sv_2394f1f864a348b596cec202828b6c36.Services
@inject ISettingsService SettingsService

<div class="p-4">
    <h4 class="mb-4">Appearance</h4>

    @if (_loading)
    {
        <div class="text-center py-5"><div class="spinner-border text-primary"></div></div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-6">
                <!-- Theme -->
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title">Theme</h6>
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check mb-2">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Font Size -->
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title">Font Size</h6>
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Language -->
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>
                </div>

                <!-- Compact Mode -->
                <div class="card mb-4">
                    <div class="card-body d-flex justify-content-between align-items-center">
                        <div>
                            <h6 class="mb-1">Compact Mode</h6>
                            <small class="text-muted">Reduce spacing and padding</small>
                        </div>
                        <div class="form-check form-switch mb-0">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_compactMode"
                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Save
                </button>
            </div>

            <!-- Live Preview -->
            <div class="col-md-6">
                <div class="card h-100">
                    <div class="card-header">
                        <h6 class="mb-0">Live Preview</h6>
                    </div>
                    <div class="card-body preview-area @PreviewThemeClass" style="@PreviewStyle">
                        <div class="@(_compactMode ? "mb-1" : "mb-3")">
                            <h5 style="@PreviewFontStyle">Dashboard</h5>
                        </div>
                        <div class="preview-card @(_compactMode ? "p-2 mb-1" : "p-3 mb-3")">
                            <p class="mb-1" style="@PreviewFontStyle"><strong>Welcome back!</strong></p>
                            <p class="mb-0 preview-muted" style="@PreviewFontStyle">You have 3 new notifications.</p>
                        </div>
                        <div class="preview-card @(_compactMode ? "p-2 mb-1" : "p-3 mb-3")">
                            <p class="mb-1" style="@PreviewFontStyle"><strong>Recent Activity</strong></p>
                            <ul class="mb-0 @(_compactMode ? "ps-3" : "")" style="@PreviewFontStyle">
                                <li>Project updated</li>
                                <li>New comment received</li>
                            </ul>
                        </div>
                        <div class="d-flex gap-2">
                            <button class="btn btn-sm preview-btn-primary" style="@PreviewFontStyle">Action</button>
                            <button class="btn btn-sm preview-btn-secondary" style="@PreviewFontStyle">Cancel</button>
                        </div>
                        <div class="mt-2">
                            <small class="preview-muted">Language: @_language</small>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _message;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string PreviewStyle => _theme == "Dark"
        ? "background: #1a1a2e; color: #e0e0e0; border-radius: 8px; min-height: 300px;"
        : "background: #ffffff; color: #212529; border-radius: 8px; min-height: 300px; border: 1px solid #dee2e6;";

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
        _saving = false;
    }
}

